document.addEventListener("DOMContentLoaded",function(){var e=document.querySelectorAll("[data-bss-chart]");for(var t of e)t.chart=new Chart(t,JSON.parse(t.dataset.bssChart));var a=document.querySelectorAll("[data-bss-swiper]"),r=document.querySelectorAll(".swiper-nav-standalone");for(var n of a){let e=JSON.parse(n.dataset.bssSwiper);if(!e.navigation){e.navigation={};for(let t of r)if(t.dataset.bssSwiperTarget==="#"+n.id){e.navigation.prevEl=t.querySelector(".swiper-button-prev"),e.navigation.nextEl=t.querySelector(".swiper-button-next");break}}new Swiper(n,e)}},!1);